CREATE TABLE "pais" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "nombre" varchar(100) NOT NULL,
  "codigo_iso" varchar(3) UNIQUE NOT NULL
);

CREATE TABLE "ciudad" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "pais_id" integer NOT NULL,
  "nombre" varchar(100) NOT NULL,
  "departamento_estado" varchar(100)
);

CREATE TABLE "negocio" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "nombre" varchar(150) NOT NULL,
  "nit_documento" varchar(50),
  "ciudad_id" integer NOT NULL,
  "direccion" varchar(255),
  "telefono" varchar(30),
  "email" varchar(150),
  "activo" boolean NOT NULL DEFAULT true,
  "creado_en" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "sucursal" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "negocio_id" integer NOT NULL,
  "nombre" varchar(150) NOT NULL,
  "ciudad_id" integer NOT NULL,
  "direccion" varchar(255),
  "telefono" varchar(30),
  "es_principal" boolean NOT NULL DEFAULT true,
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "persona" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "tipo_documento" varchar(20),
  "numero_documento" varchar(30) UNIQUE,
  "primer_nombre" varchar(100) NOT NULL,
  "segundo_nombre" varchar(100),
  "primer_apellido" varchar(100) NOT NULL,
  "segundo_apellido" varchar(100),
  "telefono" varchar(30),
  "email" varchar(150),
  "ciudad_id" integer,
  "direccion" varchar(255),
  "fecha_nacimiento" date,
  "creado_en" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "usuario" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "persona_id" integer UNIQUE NOT NULL,
  "username" varchar(100) UNIQUE,
  "email" varchar(150) UNIQUE NOT NULL,
  "password_hash" varchar(255) NOT NULL,
  "activo" boolean NOT NULL DEFAULT true,
  "ultimo_login" timestamp,
  "creado_en" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "cliente" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "persona_id" integer UNIQUE NOT NULL,
  "negocio_id" integer NOT NULL,
  "usuario_id" integer UNIQUE,
  "fecha_registro" timestamp NOT NULL DEFAULT (now()),
  "total_gastado" decimal(12,2) NOT NULL DEFAULT 0,
  "fecha_ultima_compra" timestamp,
  "numero_pedidos" integer NOT NULL DEFAULT 0,
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "cliente_preferencia" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "cliente_id" integer NOT NULL,
  "clave" varchar(100) NOT NULL,
  "valor" varchar(255) NOT NULL,
  "creado_en" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "empleado" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "persona_id" integer UNIQUE NOT NULL,
  "usuario_id" integer UNIQUE NOT NULL,
  "negocio_id" integer NOT NULL,
  "sucursal_id" integer NOT NULL,
  "rol_id" integer NOT NULL,
  "fecha_ingreso" date NOT NULL DEFAULT (now()),
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "rol" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "negocio_id" integer,
  "nombre" varchar(100) NOT NULL,
  "descripcion" varchar(255),
  "es_global" boolean NOT NULL DEFAULT false,
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "permiso" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "codigo" varchar(100) UNIQUE NOT NULL,
  "nombre" varchar(150) NOT NULL,
  "modulo" varchar(100) NOT NULL,
  "descripcion" varchar(255)
);

CREATE TABLE "rol_permiso" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "rol_id" integer NOT NULL,
  "permiso_id" integer NOT NULL
);

CREATE TABLE "turno_planificado" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "empleado_id" integer NOT NULL,
  "sucursal_id" integer NOT NULL,
  "fecha" date NOT NULL,
  "hora_inicio" time NOT NULL,
  "hora_fin" time NOT NULL,
  "creado_en" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "asistencia" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "empleado_id" integer NOT NULL,
  "turno_planificado_id" integer,
  "check_in" timestamp NOT NULL,
  "check_out" timestamp,
  "creado_en" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "comision" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "empleado_id" integer NOT NULL,
  "tipo" varchar(30) NOT NULL,
  "monto" decimal(10,2) NOT NULL,
  "referencia_id" integer,
  "fecha" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "categoria" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "negocio_id" integer NOT NULL,
  "categoria_padre_id" integer,
  "nombre" varchar(100) NOT NULL,
  "orden" integer NOT NULL DEFAULT 0,
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "producto" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "negocio_id" integer NOT NULL,
  "categoria_id" integer NOT NULL,
  "nombre" varchar(150) NOT NULL,
  "descripcion" varchar(500),
  "imagen_url" varchar(500),
  "activo" boolean NOT NULL DEFAULT true,
  "creado_en" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "producto_precio" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "producto_id" integer NOT NULL,
  "sucursal_id" integer NOT NULL,
  "precio" decimal(10,2) NOT NULL,
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "grupo_variante" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "producto_id" integer NOT NULL,
  "nombre" varchar(100) NOT NULL,
  "obligatorio" boolean NOT NULL DEFAULT true,
  "seleccion_unica" boolean NOT NULL DEFAULT true
);

CREATE TABLE "opcion_variante" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "grupo_variante_id" integer NOT NULL,
  "nombre" varchar(100) NOT NULL,
  "precio_adicional" decimal(10,2) NOT NULL DEFAULT 0,
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "adicion" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "negocio_id" integer NOT NULL,
  "nombre" varchar(100) NOT NULL,
  "precio" decimal(10,2) NOT NULL DEFAULT 0,
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "producto_adicion" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "producto_id" integer NOT NULL,
  "adicion_id" integer NOT NULL
);

CREATE TABLE "unidad_medida" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "nombre" varchar(50) NOT NULL,
  "abreviatura" varchar(10) NOT NULL,
  "unidad_base_id" integer,
  "factor_conversion" decimal(12,6)
);

CREATE TABLE "insumo" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "negocio_id" integer NOT NULL,
  "nombre" varchar(150) NOT NULL,
  "unidad_medida_id" integer NOT NULL,
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "producto_variante" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "producto_id" integer NOT NULL,
  "nombre" varchar(150),
  "activo" boolean NOT NULL DEFAULT true
);

CREATE TABLE "producto_variante_opcion" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "producto_variante_id" integer NOT NULL,
  "opcion_variante_id" integer NOT NULL
);

CREATE TABLE "receta_item" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "producto_variante_id" integer NOT NULL,
