CREATE INDEX ON "cliente_preferencia" ("cliente_id", "clave");

CREATE UNIQUE INDEX ON "rol_permiso" ("rol_id", "permiso_id");

CREATE UNIQUE INDEX ON "producto_precio" ("producto_id", "sucursal_id");

CREATE UNIQUE INDEX ON "producto_adicion" ("producto_id", "adicion_id");

CREATE UNIQUE INDEX ON "producto_variante_opcion" ("producto_variante_id", "opcion_variante_id");

CREATE UNIQUE INDEX ON "receta_item" ("producto_variante_id", "insumo_id");

CREATE UNIQUE INDEX ON "inventario_stock" ("insumo_id", "sucursal_id");

CREATE UNIQUE INDEX ON "proveedor_insumo" ("proveedor_id", "insumo_id");

CREATE UNIQUE INDEX ON "mesa" ("sucursal_id", "numero");

CREATE UNIQUE INDEX ON "producto_estacion" ("producto_id", "estacion_cocina_id");

CREATE UNIQUE INDEX ON "ruta_repartidor" ("ruta_delivery_id", "empleado_id");

CREATE UNIQUE INDEX ON "contacto_whatsapp" ("negocio_id", "telefono");

COMMENT ON TABLE "pais" IS 'Catálogo de países. Reutilizable por toda la app.';

COMMENT ON TABLE "ciudad" IS 'Catálogo de ciudades, ligado a país.';

COMMENT ON TABLE "negocio" IS 'Es el TENANT. Cada negocio es un cliente del sistema, datos aislados.';

COMMENT ON TABLE "sucursal" IS 'Hoy existe 1 fila por negocio, pero el modelo soporta N desde ya. Toda entidad operativa futura referenciará sucursal_id.';

COMMENT ON TABLE "persona" IS 'Datos humanos puros. No sabe nada de login ni de sistema. Una persona puede ser Cliente y/o Empleado a la vez.';

COMMENT ON TABLE "usuario" IS 'Solo lo necesario para login. Si la persona aún no necesita acceso al sistema (ej: cliente sin app), simplemente no tiene fila aquí.';

COMMENT ON TABLE "cliente" IS 'Un Cliente pertenece a un negocio específico. usuario_id es NULL hasta que el cliente necesite loguearse (app, fidelización futura). Los campos de resumen (total_gastado, fecha_ultima_compra, numero_pedidos) son cache calculado — el detalle real vivirá en Pedidos/Ventas cuando se diseñe ese módulo. Se actualizan desde ahí, no se editan a mano.';

COMMENT ON TABLE "cliente_preferencia" IS 'Diseño clave-valor flexible: permite agregar cualquier tipo de preferencia sin alterar el esquema (alergias, gustos, hábitos). clave no tiene catálogo fijo a propósito, para no limitar lo que el negocio puede registrar.';

COMMENT ON TABLE "empleado" IS 'Un Empleado SIEMPRE tiene Usuario (decisión confirmada: todos los roles loguean, incluso cocina/repartidor). Pertenece a un único negocio.';

COMMENT ON TABLE "rol" IS 'Roles base del sistema tienen negocio_id = NULL y es_global = true (admin, cajero, mesero, cocina, repartidor, gerente). Cada negocio puede crear los suyos con negocio_id propio.';

COMMENT ON TABLE "permiso" IS 'Catálogo fijo de acciones del sistema. Definido por el sistema, no por el negocio.';

COMMENT ON TABLE "rol_permiso" IS 'Tabla puente: qué permisos tiene cada rol.';

COMMENT ON TABLE "turno_planificado" IS 'El horario planeado de antemano para un empleado en una fecha específica. No implica que realmente haya trabajado esas horas — eso lo registra Asistencia.';

COMMENT ON TABLE "asistencia" IS 'Lo que realmente pasó: hora real de entrada/salida. Se compara contra turno_planificado para medir puntualidad, pero puede existir sin turno planificado (turno extra no programado).';

COMMENT ON TABLE "comision" IS 'Comisión generada por venta (mesero), propina, o entrega (repartidor). referencia_id queda como puente libre hacia Pedidos/Ventas/Delivery, módulos aún no diseñados.';

COMMENT ON TABLE "categoria" IS 'Jerarquía vía auto-referencia: Comidas > Carnes > Res. categoria_padre_id null = nivel raíz.';

COMMENT ON TABLE "producto" IS 'El producto base, sin precio (el precio vive en producto_precio, por sucursal). Variantes y adiciones se modelan aparte.';

COMMENT ON TABLE "producto_precio" IS 'Mismo producto puede tener precio distinto por sucursal. Hoy con 1 sucursal hay 1 fila por producto, pero el modelo ya soporta N.';

COMMENT ON TABLE "grupo_variante" IS 'Agrupa opciones excluyentes entre sí, ej: "Tamaño" agrupa Pequeño/Grande. Un producto puede tener varios grupos (Tamaño + Tipo de carne).';

COMMENT ON TABLE "opcion_variante" IS 'Una opción dentro de un grupo de variante. precio_adicional puede ser 0 (sin costo extra) o positivo (ej: Grande +$3000).';

COMMENT ON TABLE "adicion" IS 'Catálogo de adiciones a nivel de negocio, reutilizable entre productos (ej: "Queso extra" aplica a varias hamburguesas).';

COMMENT ON TABLE "producto_adicion" IS 'Tabla puente: qué adiciones están disponibles para cada producto. El precio de la adición se toma de adicion.precio (puede sobreescribirse aquí si en el futuro un producto necesita un precio distinto para la misma adición).';

COMMENT ON TABLE "unidad_medida" IS 'Catálogo de unidades. Cada "familia" (peso, volumen, unidad) tiene una unidad base (ej: Gramo para peso). factor_conversion convierte hacia esa base: kg.factor_conversion = 1000 significa 1kg = 1000g.';

COMMENT ON TABLE "insumo" IS 'Versión mínima para que Receta tenga a qué apuntar. Stock, movimientos y alertas de stock bajo se diseñan en el módulo de Inventario.';

COMMENT ON TABLE "producto_variante" IS 'Representa UNA combinación específica de opciones de variante para un producto (ej: Grande + Res). La receta se ancla aquí, no en producto directamente, porque cada combinación consume insumos distinto.';

COMMENT ON TABLE "producto_variante_opcion" IS 'Tabla puente: qué opciones (de qué grupos de variante) componen esta combinación concreta. Ej: producto_variante "Grande-Res" = opcion "Grande" + opcion "Res".';

COMMENT ON TABLE "receta_item" IS 'Cada fila = "esta combinación de producto consume X cantidad de este insumo". unidad_medida_id permite que la receta diga "150 g" aunque el insumo se almacene en kg — la conversión se resuelve con unidad_medida.factor_conversion al descontar inventario.';

COMMENT ON TABLE "inventario_stock" IS 'Cache del stock actual por insumo+sucursal. Es la fuente RÁPIDA de consulta (ej: "¿hay suficiente queso para esta receta?"). Se actualiza a partir de movimiento_inventario, nunca se edita directo a mano — así el número siempre coincide con la suma de su historial.';

COMMENT ON TABLE "movimiento_inventario" IS 'Historial inmutable y fuente de verdad del inventario. cantidad_actual en inventario_stock se recalcula/actualiza a partir de esta tabla. referencia_id queda como puente libre hacia Compras/Pedidos, igual que hicimos en comision.referencia_id.';

COMMENT ON TABLE "proveedor" IS 'Catálogo de proveedores por negocio.';

COMMENT ON TABLE "proveedor_insumo" IS 'Lista de precios del proveedor. precio_referencia es orientativo — el precio real de cada compra se registra en orden_compra_item, porque puede negociarse o cambiar.';

COMMENT ON TABLE "solicitud_compra" IS 'Solicitud inicial, puede originarse manualmente o por alerta de stock bajo (inventario_stock.cantidad_actual < stock_minimo). Requiere aprobación de un rol autorizado antes de generar la Orden de Compra.';

COMMENT ON TABLE "solicitud_compra_item" IS 'Insumos y cantidades pedidas en la solicitud. No incluye proveedor ni precio todavía — eso se decide al generar la Orden de Compra.';

COMMENT ON TABLE "orden_compra" IS 'Se genera solo a partir de una solicitud_compra ya aprobada. estado refleja si ya se recibió la mercancía (parcial o completa) — es independiente de estado_pago, porque puede recibirse en crédito sin haber pagado. estado_pago se recalcula cada vez que se inserta una fila en pago_compra (pendiente: $0 pagado; pago_parcial: 0 < pagado < total; pagada: pagado >= total). No se edita a mano, igual que inventario_stock con sus movimientos.';

COMMENT ON TABLE "orden_compra_item" IS 'cantidad_recibida < cantidad_pedida indica recepción parcial. Cada recepción de mercancía actualiza este campo y genera un movimiento_inventario tipo entrada.';

COMMENT ON TABLE "pago_compra" IS 'Cada abono es una fila independiente. El saldo pendiente de la orden_compra = total - SUM(pago_compra.monto) de sus pagos. Permite crédito con el proveedor vía pagos parciales.';

COMMENT ON TABLE "categoria_gasto" IS 'Catálogo de categorías de gasto por negocio, para poder reportar por categoría.';

COMMENT ON TABLE "gasto" IS 'Gastos operativos que NO son compra de insumos (esos viven en orden_compra). Ej: pago de luz, arriendo, nómina, reparación de equipo.';

COMMENT ON TABLE "credito_cliente" IS 'Una deuda de un cliente con el negocio (fiado). Mismo patrón que orden_compra: estado_pago se recalcula a partir de sus abonos, no se edita a mano.';

COMMENT ON TABLE "abono_credito_cliente" IS 'Cada abono del cliente es una fila independiente, igual que pago_compra. El saldo pendiente = monto_total - SUM(abono_credito_cliente.monto).';

COMMENT ON TABLE "caja_sesion" IS 'Una sesión de caja física por sucursal (por turno o por día, según cómo opere cada negocio). diferencia revela sobrantes/faltantes al momento del cierre. Se conecta con Personal y Turnos: normalmente abre/cierra quien está de turno.';

COMMENT ON TABLE "movimiento_caja" IS 'Cada movimiento de dinero dentro de una sesión de caja. monto_esperado_cierre en caja_sesion se calcula sumando estos movimientos filtrados por metodo=efectivo. Es el historial real, igual patrón que movimiento_inventario.';

COMMENT ON TABLE "mesa" IS 'Mesas del salón por sucursal. estado se actualiza cuando se abre/cierra un pedido tipo "mesa".';

COMMENT ON TABLE "pedido" IS 'Tabla central de toda venta. canal define mesa/llevar/delivery de forma fija. Mientras estado = "abierto" se pueden agregar/quitar pedido_item. Al pagar completo, estado pasa a "pagado" — desde ahí ya no se edita.';

COMMENT ON TABLE "pedido_item" IS 'Cada línea del pedido. Se puede agregar/quitar mientras pedido.estado = "abierto". estado propio permite que Cocina (KDS, módulo futuro) marque item por item, no todo el pedido junto.';

COMMENT ON TABLE "pedido_item_adicion" IS 'Adiciones elegidas para este item específico (ej: este pedido_item de hamburguesa lleva "Queso extra"). precio_aplicado se copia, no se recalcula si el precio de la adición cambia después.';

COMMENT ON TABLE "pago_pedido" IS 'Cada fila es un pago parcial. Un pedido puede tener N filas (split entre métodos o comensales). pedido.estado pasa a "pagado" cuando SUM(pago_pedido.monto) >= pedido.total. Si metodo = "credito_cliente", se genera un credito_cliente en vez de un movimiento_caja inmediato.';

COMMENT ON TABLE "estacion_cocina" IS 'Estaciones de cocina por sucursal. Cada negocio define las suyas (no hay catálogo fijo, porque varía mucho entre restaurantes).';

COMMENT ON TABLE "producto_estacion" IS 'A qué estación pertenece este producto (ej: Hamburguesa → Parrilla). Se hereda automáticamente al pedido_item_estacion cuando se crea el pedido, así cocina no tiene que clasificar manualmente cada vez.';

COMMENT ON TABLE "pedido_item_estacion" IS 'Seguimiento real por estación. Heredado de producto_estacion al crear el pedido_item. Permite medir tiempos por estación (listo_en - entro_en) y que cada estación vea solo lo suyo en su pantalla KDS. Cuando TODAS las filas de un pedido_item quedan en "listo", se actualiza pedido_item.estado a "listo".';

COMMENT ON TABLE "ruta_delivery" IS 'Zona de reparto. MVP: zonas_cubiertas es texto libre con los barrios. Futuro: se reemplaza/complementa por radio de coordenadas + algoritmo de cercanía, sin romper el modelo porque pedido_delivery ya guarda lat/long.';

COMMENT ON TABLE "ruta_repartidor" IS 'Qué repartidores pertenecen a cada ruta. Puede ser uno o varios por ruta, como confirmaste — de ahí se elige el disponible al momento de asignar.';

COMMENT ON TABLE "salida_reparto" IS 'Una "vuelta" de reparto: un repartidor, varios pedidos posibles (confirmado: puede llevar 3 domicilios en una salida). Se elige repartidor disponible de ruta_repartidor para esa ruta.';

COMMENT ON TABLE "pedido_delivery" IS 'Datos específicos de un pedido cuando canal = "delivery". latitud/longitud existen desde el MVP aunque la asignación de ruta hoy se haga por "barrio" en texto — así el futuro algoritmo de cercanía no requiere migración, solo empieza a leer estos campos.';

COMMENT ON TABLE "anulacion" IS 'requiere_autorizacion se calcula al crear la anulación: true si el pedido ya estaba "pagado" (necesita Gerente u otro rol autorizado), false si seguía "abierto" (el mismo empleado puede anular directo, estado queda en "aprobada" automáticamente). pedido_item_id null = anula el pedido completo; con valor = anulación parcial de un solo item.';

COMMENT ON TABLE "comprobante_impresion" IS 'Registro de cada vez que se imprime el comprobante de un pedido. es_reimpresion distingue la original de copias posteriores — útil para detectar reimpresiones sospechosas en auditoría. No almacena el contenido del comprobante (eso se genera al momento desde pedido + pedido_item), solo el registro de que se imprimió.';

COMMENT ON TABLE "contacto_whatsapp" IS 'Contacto ligero por negocio. NO es Persona ni Cliente — solo guarda el último dato dado para no volver a preguntarlo. telefono es único POR NEGOCIO (un mismo número puede escribirle a 2 negocios distintos del sistema).';

COMMENT ON TABLE "conversacion_whatsapp" IS 'Agrupa los mensajes de una sesión de chat. estado controla si responde el LLM o un humano tomó el control. empleado_id se llena solo cuando un humano interviene.';

COMMENT ON TABLE "mensaje_whatsapp" IS 'Cada mensaje individual. emisor_tipo distingue si lo escribió el cliente, el LLM, o un empleado humano que tomó el control. Diseño flexible: no requiere 3 tablas separadas por tipo de emisor.';

